import java.io.*;
import java.nio.charset.StandardCharsets;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        // Read entire input as a raw string
        InputStream in = System.in;
        byte[] allBytes = in.readAllBytes();
        String data = new String(allBytes, StandardCharsets.UTF_8);
        // Replace escaped "\n" sequences with a space so they are treated as separators
        data = data.replace("\\n", " ");
        // Use a Scanner on the cleaned data
        Scanner sc = new Scanner(data);
        StringBuilder sb = new StringBuilder();
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int Y = sc.nextInt();
            int cur = 0;
            for (int i = 0; i < N; i++) {
                cur |= sc.nextInt();
            }
            // If current OR has a bit that Y does not have, impossible
            if ((cur & ~Y) != 0) {
                sb.append("-1\n");
            } else {
                int X = Y & ~cur; // set exactly the missing bits
                sb.append(X).append('\n');
            }
        }
        System.out.print(sb.toString());
    }
}

